<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Request { private array $arguments = []; function __construct() { global $argv; array_shift($argv); $key = ''; foreach ($argv as $i => $argument) { if (str_starts_with($argument, '--') && strlen($argument) > 2) { $key = substr($argument, 2); if (!isset($this->arguments[$key])) $this->arguments[$key] = []; } elseif ($key) $this->arguments[$key][] = $argument; else $this->arguments[$i] = $argument; } } function getArgument(string $key, mixed $fallback = null): mixed { return $this->arguments[$key] ?? $fallback; } function getArguments(): object { return (object) $this->arguments; } function updateArguments(array $arguments): void { $this->arguments = $arguments; } } 